  // ...other validation fields for enabled: true
});

const SectionADisabled = z.object({
  type: z.literal("A"),
  enabled: z.literal(false),
}).passthrough();

const SectionAUnion = z.union([SectionA, SectionADisabled]);
```

You can repeat this for each section type and then create a discriminated union:

```ts
const Sections = z.discriminatedUnion("type", [
  SectionAUnion,
  // SectionBUnion, SectionCUnion, etc.
]);
```

