2. **Collect base errors** from the result (if any).
3. **Manually run your cross-field/object-level checks** on the raw input, regardless of whether base validation passed, and collect any errors as Zod-style issues (with `code`, `message`, and `path`).
4. **Merge all errors** into a single array.
5. **Format the merged errors** using Zod's `flattenError` or `treeifyError` utility for easy consumption by your form library.

Here’s a simplified example based on your schema:

```typescript
import { z } from "zod";

// 1. Your Zod schema (without object-level .refine for this pattern)
const YesEventSchema = z.object({
  hasEventActivity: z.literal("YES"),
  categoryType: z.string().nullable(),
  purposeForEvent: z.string(),
  otherPurposeForEvent: z.string().optional(),
  hasRelocated: z.string().nullable(),
  engagementPercentage: z.number().nullable(),
  // ...other fields
});

const NoEventSchema = z.object({
  hasEventActivity: z.literal("NO"),
});

const eventActivitySchema = z.discriminatedUnion("hasEventActivity", [
  NoEventSchema,
  YesEventSchema,
]);

// 2. Manual cross-field checks
function manualRefinements(data: any) {
  const issues: z.ZodIssue[] = [];

  if (
    data.hasEventActivity === "YES" &&
    data.purposeForEvent === "CUSTOM_OPTION_VALUE" &&
    !data.otherPurposeForEvent
  ) {
    issues.push({
      code: "custom",
      message: "Please specify the other purpose for event",
      path: ["otherPurposeForEvent"],
    });
  }

  if (
    data.hasEventActivity === "YES" &&
    data.categoryType === "IN_PERSON" &&
    data.hasRelocated == null
  ) {
    issues.push({
      code: "custom",
      message: "Please select an option",
      path: ["hasRelocated"],
    });
  }

  if ("},{"type":"text","text":"
    data.hasEventActivity === "YES" &&
    data.categoryType === "IN_PERSON" &&
    data.hasRelocated === "YES" &&
    data.engagementPercentage == null
  ) {
    issues.push({
      code: "custom",
      message: "Engagement percentage is required",
      path: ["engagementPercentage"],
    });
  }

  return issues;
}

// 3. Validation function for your form
function validateForm(formData: any) {
  // Run base Zod validation
  const baseResult = eventActivitySchema.safeParse(formData);
  const baseErrors = baseResult.success ? [] : baseResult.error.issues;

  // Always run manual refinements
  const refinementErrors = manualRefinements(formData);

  // Merge all errors
  const allIssues = [...baseErrors, ...refinementErrors];

  // Format for form UI (e.g., TanStack Form)
  // Use flattenError for a flat structure, or treeifyError for nested
  const formatted = z.flattenError({ issues: allIssues });

  return {
    valid: allIssues.length === 0,
    errors: formatted,
  };
}
```

Now, `validateForm(formData)` will return all relevant errors, including cross-field ones, in a structure that's easy to map to your form fields. You can use `formatted.fieldErrors` and `formatted.formErrors` in your UI.

- [See Zod error formatting docs](https://zod.dev/error-formatting)
- [See related discussion and more patterns](https://github.com/colinhacks/zod/issues/4738)

