{"file_path": "/mnt/vdb/djc/work_djc/interactive_data_generation-master_multi_domain_new_struct/workspace/zod--kongyo2_claude_code_203/src/schemas/checkout.schema.ts", "content": "/**
 * E-Commerce Checkout Validation Schema
 * ======================================
 *
 * This module demonstrates Zod v4 best practices for:
 * - Discriminated unions with conditional fields
 * - Cross-field validation using refinements
 * - Custom error messages with proper error mapping
 * - JSON Schema conversion for OpenAPI integration
 * - Metadata management with registries
 *
 * Payment Methods: credit_card, bank_transfer, digital_wallet
 * Shipping Options: pickup, delivery, express
 * Customer Types: individual, business
 */

import * as z from "zod";

// ============================================================================
// CUSTOM ERROR MESSAGES & ERROR FORMATTING UTILITIES
// ============================================================================

/**
 * Custom error messages for frontend localization support
 */
export const errorMessages = {
  // Type errors
  required: (field: string) => `${field} is required`,
  invalidType: (field: string, expected: string) =>
    `${field} must be a ${expected}`,

  // String validation
  minLength: (field: string, min: number) =>
    `${field} must be at least ${min} characters`,
  maxLength: (field: string, max: number) =>
    `${field} must be at most ${max} characters`,
  invalidEmail: "Please enter a valid email address",
  invalidPhone: "Please enter a valid phone number",

  // Payment specific
  invalidCardNumber: "Please enter a valid card number (16 digits)",
  invalidCVV: "CVV must be 3 or 4 digits",
  invalidExpiry: "Please enter a valid expiry date (MM/YY)",
  cardExpired: "Card has expired",

  // Bank transfer specific
  invalidAccountNumber: "Account number must be 8-17 digits",
  invalidRoutingNumber: "Routing number must be 9 digits",
  invalidIBAN: "Please enter a valid IBAN",
  invalidSWIFT: "Please enter a valid SWIFT/BIC code",

  // Digital wallet specific
  invalidWalletId: "Invalid wallet identifier",
  walletNotSupported: "This wallet type is not supported",

  // Shipping specific
  invalidPostalCode: (country: string) =>
    `Invalid postal code format for ${country}`,
  invalidAddress: "Please enter a complete address",

  // Business specific
  invalidVAT: "Please enter a valid VAT number",
  invalidTaxId: "Please enter a valid Tax ID",

  // Cross-field validation
  billingShippingMismatch: "Billing and shipping addresses must match for pickup orders",
  expressRequiresDelivery: "Express shipping requires a delivery address",
  businessVATRequired: "Business customers must provide a VAT number for EU orders",
  walletInsufficientFunds: "Insufficient funds in digital wallet",
};

/**
 * Error mapping utility for frontend form libraries
 * Converts ZodError issues to a field-based error map
 */
export function mapErrorsToFields<T>(
  error: z.ZodError
): Record<string, string[]> {
  const fieldErrors: Record<string, string[]> = {};

  for (const issue of error.issues) {
    const path = issue.path.join(".");
    if (!fieldErrors[path]) {
      fieldErrors[path] = [];
    }
    fieldErrors[path].push(issue.message);
  }

  return fieldErrors;
}

/**
 * Error tree structure for nested form errors
 */
export interface ErrorTree {
  errors: string[];
  properties?: Record<string, ErrorTree>;
  items?: (ErrorTree | undefined)[];
}

/**
 * Map ZodError to a nested tree structure for complex forms
 */
export function mapErrorsToTree(error: z.ZodError): ErrorTree {
  return z.treeifyError(error) as ErrorTree;
}

/**
 * Flatten errors for simple form integration (e.g., React Hook Form)
 */
export function flattenErrors(error: z.ZodError): {
  formErrors: string[];
  fieldErrors: Record<string, string[]>;
} {
  return z.flattenError(error);
}

/**
 * Format error for display (human-readable)
 */
export function formatErrorForDisplay(error: z.ZodError): string {
  return z.prettifyError(error);
}

// ============================================================================
// BASE SCHEMAS WITH METADATA
// ============================================================================

/**
 * Address schema with comprehensive validation
 */
const AddressSchema = z.object({
  line1: z.string()
    .min(1, { error: errorMessages.required("Address line 1") })
    .max(100, { error: errorMessages.maxLength("Address line 1", 100) })
    .meta({
      title: "Address Line 1",
      description: "Street address, P.O. box, company name",
      placeholder: "123 Main Street",
    }),

  line2: z.string()
    .max(100, { error: errorMessages.maxLength("Address line 2", 100) })
    .optional()
    .meta({
      title: "Address Line 2",
      description: "Apartment, suite, unit, building, floor, etc.",
      placeholder: "Apt 4B",
    }),

  city: z.string()
    .min(1, { error: errorMessages.required("City") })
    .max(50, { error: errorMessages.maxLength("City", 50) })
    .meta({
      title: "City",
      description: "City or locality",
    }),

  state: z.string()
    .min(1, { error: errorMessages.required("State/Province") })
    .max(50, { error: errorMessages.maxLength("State/Province", 50) })
    .meta({
      title: "State/Province",
      description: "State, province, or region",
    }),

  postalCode: z.string()
    .min(1, { error: errorMessages.required("Postal code") })
    .max(20, { error: errorMessages.maxLength("Postal code", 20) })
    .meta({
      title: "Postal Code",
      description: "ZIP or postal code",
    }),

  country: z.string()
    .min(2, { error: errorMessages.required("Country") })
    .max(2, { error: "Country must be a 2-letter ISO code" })
    .meta({
      title: "Country",
      description: "Two-letter ISO country code",
      examples: ["US", "GB", "DE", "FR"],
    }),
}).meta({
  id: "Address",
  title: "Address",
  description: "A complete postal address",
});

/**
 * Contact information schema
 */
const ContactSchema = z.object({
  email: z.email({ error: errorMessages.invalidEmail })
    .meta({
      title: "Email Address",
      description: "We'll send order confirmation here",
      placeholder: "you@example.com",
    }),

  phone: z.string()
    .min(10, { error: errorMessages.invalidPhone })
    .max(20, { error: errorMessages.invalidPhone })
    .meta({
      title: "Phone Number",
      description: "For delivery updates and support",
      placeholder: "+1 (555) 123-4567",
    }),

  firstName: z.string()
    .min(1, { error: errorMessages.required("First name") })
    .max(50, { error: errorMessages.maxLength("First name", 50) })
    .meta({ title: "First Name" }),

  lastName: z.string()
    .min(1, { error: errorMessages.required("Last name") })
    .max(50, { error: errorMessages.maxLength("Last name", 50) })
    .meta({ title: "Last Name" }),
}).meta({
  id: "Contact",
  title: "Contact Information",
  description: "Primary contact details for the order",
});

// ============================================================================
// PAYMENT METHOD SCHEMAS (DISCRIMINATED UNION)
// ============================================================================

/**
 * Credit Card Payment Schema
 */
const CreditCardPaymentSchema = z.object({
  method: z.literal("credit_card"),

  cardNumber: z.string()
    .length(16, { error: errorMessages.invalidCardNumber })
    .regex(/^\d{16}$/, { error: errorMessages.invalidCardNumber })
    .meta({
      title: "Card Number",
      description: "16-digit card number without spaces",
      placeholder: "4242424242424242",
    }),

  cardholderName: z.string()
    .min(1, { error: errorMessages.required("Cardholder name") })
    .max(100, { error: errorMessages.maxLength("Cardholder name", 100) })
    .meta({
      title: "Cardholder Name",
      description: "Name as it appears on the card",
    }),

  expiryMonth: z.string()
    .length(2, { error: errorMessages.invalidExpiry })
    .regex(/^(0[1-9]|1[0-2])$/, { error: errorMessages.invalidExpiry })
    .meta({
      title: "Expiry Month",
      description: "Two-digit month (01-12)",
      placeholder: "12",
    }),

  expiryYear: z.string()
    .length(2, { error: errorMessages.invalidExpiry })
    .regex(/^\d{2}$/, { error: errorMessages.invalidExpiry })
    .meta({
      title: "Expiry Year",
      description: "Two-digit year",
      placeholder: "28",
    }),

  cvv: z.string()
    .length(3, { error: errorMessages.invalidCVV })
    .regex(/^\d{3,4}$/, { error: errorMessages.invalidCVV })
    .meta({
      title: "CVV",
      description: "3 or 4 digit security code",
      placeholder: "123",
    }),

  saveCard: z.boolean()
    .default(false)
    .meta({
      title: "Save Card",
      description: "Save card for future purchases",
    }),
}).meta({
  id: "CreditCardPayment",
  title: "Credit Card Payment",
  description: "Payment via credit or debit card",
});

/**
 * Bank Transfer Payment Schema
 */
const BankTransferPaymentSchema = z.object({
  method: z.literal("bank_transfer"),

  accountType: z.enum(["checking", "savings"])
    .meta({
      title: "Account Type",
      description: "Type of bank account",
    }),

  // US Domestic Bank Transfer
  accountNumber: z.string()
    .min(8, { error: errorMessages.invalidAccountNumber })
    .max(17, { error: errorMessages.invalidAccountNumber })
    .regex(/^\d+$/, { error: errorMessages.invalidAccountNumber })
    .optional()
    .meta({
      title: "Account Number",
      description: "Bank account number (8-17 digits)",
    }),

  routingNumber: z.string()
    .length(9, { error: errorMessages.invalidRoutingNumber })
    .regex(/^\d{9}$/, { error: errorMessages.invalidRoutingNumber })
    .optional()
    .meta({
      title: "Routing Number",
      description: "9-digit bank routing number (US)",
    }),

  // International Bank Transfer (SWIFT/IBAN)
  iban: z.string()
    .min(15, { error: errorMessages.invalidIBAN })
    .max(34, { error: errorMessages.invalidIBAN })
    .regex(/^[A-Z]{2}\d{2}[A-Z0-9]+$/, { error: errorMessages.invalidIBAN })
    .optional()
    .meta({
      title: "IBAN",
      description: "International Bank Account Number (non-US)",
    }),

  swiftCode: z.string()
    .length(8, { error: errorMessages.invalidSWIFT })
    .or(z.string().length(11, { error: errorMessages.invalidSWIFT }))
    .regex(/^[A-Z]{4}[A-Z]{2}[A-Z0-9]{2}([A-Z0-9]{3})?$/, {
      error: errorMessages.invalidSWIFT
    })
    .optional()
    .meta({
      title: "SWIFT/BIC Code",
      description: "Bank identifier code for international transfers",
    }),

  accountHolderName: z.string()
    .min(1, { error: errorMessages.required("Account holder name") })
    .max(100, { error: errorMessages.maxLength("Account holder name", 100) })
    .meta({
      title: "Account Holder Name",
      description: "Name of the account holder",
    }),

  bankName: z.string()
    .min(1, { error: errorMessages.required("Bank name") })
    .max(100, { error: errorMessages.maxLength("Bank name", 100) })
    .meta({
      title: "Bank Name",
      description: "Name of the bank",
    }),
}).meta({
  id: "BankTransferPayment",
  title: "Bank Transfer Payment",
  description: "Payment via direct bank transfer",
}).refine(
  // Ensure either US or International banking details are provided
  (data) => {
    const hasUSDetails = data.accountNumber && data.routingNumber;
    const hasIntlDetails = data.iban && data.swiftCode;
    return !!(hasUSDetails || hasIntlDetails);
  },
  {
    error: "Please provide either US banking details (account + routing number) or international details (IBAN + SWIFT)",
    path: ["accountNumber"],
  }
);

/**
 * Digital Wallet Payment Schema
 */
const DigitalWalletPaymentSchema = z.object({
  method: z.literal("digital_wallet"),

  walletType: z.enum(["apple_pay", "google_pay", "paypal", "venmo", "stripe_link"])
    .meta({
      title: "Wallet Type",
      description: "Digital wallet provider",
    }),

  walletId: z.string()
    .min(1, { error: errorMessages.invalidWalletId })
    .meta({
      title: "Wallet ID",
      description: "Identifier for the digital wallet",
    }),

  // Pre-authorized payment token from wallet provider
  paymentToken: z.string()
    .min(1, { error: "Payment authorization required" })
    .meta({
      title: "Payment Token",
      description: "Pre-authorized payment token from wallet provider",
    }),

  // Billing address (required by most wallet providers)
  billingAddress: AddressSchema,

  // Device/browser information for fraud prevention
  deviceId: z.string()
    .optional()
    .meta({
      title: "Device ID",
      description: "Device identifier for fraud prevention",
    }),
}).meta({
  id: "DigitalWalletPayment",
  title: "Digital Wallet Payment",
  description: "Payment via digital wallet (Apple Pay, Google Pay, PayPal, etc.)",
});

/**
 * Payment Method Discriminated Union
 * Uses z.discriminatedUnion for efficient parsing and TypeScript narrowing
 */
const PaymentSchema = z.discriminatedUnion("method", [
  CreditCardPaymentSchema,
  BankTransferPaymentSchema,
  DigitalWalletPaymentSchema,
]).meta({
  id: "Payment",
  title: "Payment Information",
  description: "Payment method and details",
});

// ============================================================================
// SHIPPING OPTION SCHEMAS (DISCRIMINATED UNION)
// ============================================================================

/**
 * Pickup Shipping Schema
 */
const PickupShippingSchema = z.object({
  option: z.literal("pickup"),

  pickupLocationId: z.string()
    .min(1, { error: "Please select a pickup location" })
    .meta({
      title: "Pickup Location",
      description: "Store or pickup point ID",
    }),

  pickupDate: z.string()
    .regex(/^\d{4}-\d{2}-\d{2}$/, { error: "Please select a valid pickup date" })
    .meta({
      title: "Pickup Date",
      description: "Preferred pickup date (YYYY-MM-DD)",
    }),

  pickupTime: z.string()
    .regex(/^\d{2}:\d{2}$/, { error: "Please select a valid pickup time" })
    .optional()
    .meta({
      title: "Pickup Time",
      description: "Preferred pickup time (HH:MM)",
    }),

  // Pickup contact (may differ from order contact)
  pickupContact: z.object({
    name: z.string().min(1, { error: errorMessages.required("Pickup contact name") }),
    phone: z.string().min(10, { error: errorMessages.invalidPhone }),
  }).optional()
    .meta({
      title: "Pickup Contact",
      description: "Person who will pick up the order",
    }),
}).meta({
  id: "PickupShipping",
  title: "Store Pickup",
  description: "Pick up at a store or pickup point",
});

/**
 * Standard Delivery Shipping Schema
 */
const DeliveryShippingSchema = z.object({
  option: z.literal("delivery"),

  shippingAddress: AddressSchema,

  deliveryInstructions: z.string()
    .max(500, { error: errorMessages.maxLength("Delivery instructions", 500) })
    .optional()
    .meta({
      title: "Delivery Instructions",
      description: "Special instructions for delivery",
      placeholder: "Leave at door, ring doorbell, etc.",
    }),

  signatureRequired: z.boolean()
    .default(false)
    .meta({
      title: "Signature Required",
      description: "Require signature on delivery",
    }),

  // Delivery preferences
  preferredDeliveryDate: z.string()
    .regex(/^\d{4}-\d{2}-\d{2}$/, { error: "Please select a valid delivery date" })
    .optional()
    .meta({
      title: "Preferred Delivery Date",
      description: "Preferred delivery date (YYYY-MM-DD)",
    }),

  preferredDeliveryTime: z.enum(["morning", "afternoon", "evening"])
    .optional()
    .meta({
      title: "Preferred Delivery Time",
      description: "Preferred time window",
    }),
}).meta({
  id: "DeliveryShipping",
  title: "Standard Delivery",
  description: "Home or business delivery",
});

/**
 * Express Shipping Schema
 * Has additional requirements for expedited delivery
 */
const ExpressShippingSchema = z.object({
  option: z.literal("express"),

  shippingAddress: AddressSchema,

  // Express delivery time slot (required)
  deliverySlot: z.enum(["same_day", "next_morning", "next_afternoon", "next_evening"])
    .meta({
      title: "Delivery Time Slot",
      description: "Express delivery time slot",
    }),

  // Phone required for express (for delivery updates)
  deliveryPhone: z.string()
    .min(10, { error: errorMessages.invalidPhone })
    .meta({
      title: "Delivery Contact Phone",
      description: "Phone number for delivery updates",
    }),

  deliveryInstructions: z.string()
    .max(500, { error: errorMessages.maxLength("Delivery instructions", 500) })
    .optional()
    .meta({
      title: "Delivery Instructions",
      description: "Special instructions for delivery",
    }),

  // Express specific options
  leaveAtDoor: z.boolean()
    .default(false)
    .meta({
      title: "Leave at Door",
      description: "Leave package at door if no one is home",
    }),

  // Additional fee acknowledgment
  expressFeeAcknowledged: z.boolean()
    .refine((val) => val === true, {
      error: "Please acknowledge the express delivery fee"
    })
    .meta({
      title: "Express Fee",
      description: "I understand there is an additional fee for express delivery",
    }),
}).meta({
  id: "ExpressShipping",
  title: "Express Delivery",
  description: "Same-day or next-day delivery",
});

/**
 * Shipping Option Discriminated Union
 */
const ShippingSchema = z.discriminatedUnion("option", [
  PickupShippingSchema,
  DeliveryShippingSchema,
  ExpressShippingSchema,
]).meta({
  id: "Shipping",
  title: "Shipping Information",
  description: "Shipping method and delivery details",
});

// ============================================================================
// CUSTOMER TYPE SCHEMAS (DISCRIMINATED UNION)
// ============================================================================

/**
 * Individual Customer Schema
 */
const IndividualCustomerSchema = z.object({
  type: z.literal("individual"),

  contact: ContactSchema,

  // Optional loyalty program
  loyaltyProgramId: z.string()
    .optional()
    .meta({
      title: "Loyalty Program ID",
      description: "Loyalty or rewards program membership",
    }),

  // Marketing preferences
  marketingOptIn: z.boolean()
    .default(false)
    .meta({
      title: "Marketing Opt-In",
      description: "Receive promotional emails and offers",
    }),
}).meta({
  id: "IndividualCustomer",
  title: "Individual Customer",
  description: "Personal shopper account",
});

/**
 * Business Customer Schema
 * Requires additional business information
 */
const BusinessCustomerSchema = z.object({
  type: z.literal("business"),

  contact: ContactSchema,

  // Business information (required for B2B)
  companyName: z.string()
    .min(1, { error: errorMessages.required("Company name") })
    .max(200, { error: errorMessages.maxLength("Company name", 200) })
    .meta({
      title: "Company Name",
      description: "Legal name of the business",
    }),

  // Tax identification (varies by country)
  vatNumber: z.string()
    .optional()
    .meta({
      title: "VAT Number",
      description: "VAT registration number (EU)",
    }),

  taxId: z.string()
    .optional()
    .meta({
      title: "Tax ID",
      description: "Federal Tax ID / EIN (US)",
    }),

  // Business address (for invoicing)
  businessAddress: AddressSchema,

  // Purchase order information
  purchaseOrderNumber: z.string()
    .max(50, { error: errorMessages.maxLength("PO number", 50) })
    .optional()
    .meta({
      title: "Purchase Order Number",
      description: "For corporate procurement",
    }),

  // Business-specific settings
  requireInvoice: z.boolean()
    .default(true)
    .meta({
      title: "Require Invoice",
      description: "Generate invoice for accounting",
    }),

  // Accounts payable contact
  accountsPayableEmail: z.email()
    .optional()
    .meta({
      title: "Accounts Payable Email",
      description: "Email for invoice delivery",
    }),
}).meta({
  id: "BusinessCustomer",
  title: "Business Customer",
  description: "B2B customer with business information",
}).refine(
  // Require either VAT or Tax ID for business customers
  (data) => !!(data.vatNumber || data.taxId),
  {
    error: "Business customers must provide a VAT number (EU) or Tax ID (US)",
    path: ["vatNumber"],
  }
);

/**
 * Customer Type Discriminated Union
 */
const CustomerSchema = z.discriminatedUnion("type", [
  IndividualCustomerSchema,
  BusinessCustomerSchema,
]).meta({
  id: "Customer",
  title: "Customer Information",
  description: "Customer type and details",
});

// ============================================================================
// COMPLETE CHECKOUT SCHEMA WITH CROSS-FIELD VALIDATION
// ============================================================================

/**
 * Checkout Form Step Schemas
 * For multi-step form implementation
 */
export const CheckoutStepSchemas = {
  step1_customer: CustomerSchema,
  step2_shipping: ShippingSchema,
  step3_payment: PaymentSchema,
} as const;

/**
 * Complete Checkout Schema
 * Combines all schemas with cross-field validation
 */
const CheckoutSchema = z.object({
  // Unique identifiers
  cartId: z.string()
    .min(1, { error: "Cart ID is required" })
    .meta({ title: "Cart ID" }),

  orderId: z.string()
    .optional()
    .meta({ title: "Order ID" }),

  // Customer information
  customer: CustomerSchema,

  // Shipping method and details
  shipping: ShippingSchema,

  // Payment method and details
  payment: PaymentSchema,

  // Billing address (may differ from shipping)
  billingAddress: AddressSchema.optional(),

  // Same as shipping flag
  billingSameAsShipping: z.boolean()
    .default(true)
    .meta({
      title: "Billing Same as Shipping",
      description: "Use shipping address for billing",
    }),

  // Order notes
  orderNotes: z.string()
    .max(1000, { error: errorMessages.maxLength("Order notes", 1000) })
    .optional()
    .meta({
      title: "Order Notes",
      description: "Special requests or notes for this order",
    }),

  // Terms and conditions
  termsAccepted: z.boolean()
    .refine((val) => val === true, {
      error: "You must accept the terms and conditions"
    })
    .meta({
      title: "Terms Accepted",
      description: "I accept the terms and conditions",
    }),

  // Timestamp
  createdAt: z.string()
    .optional()
    .meta({ title: "Created At" }),
}).meta({
  id: "Checkout",
  title: "Checkout",
  description: "Complete checkout form submission",
}).check((ctx) => {
  const data = ctx.value;

  // Rule 1: Billing address required if billingSameAsShipping is false
  if (!data.billingSameAsShipping && !data.billingAddress) {
    ctx.issues.push({
      code: "custom",
      message: "Billing address is required when not using shipping address",
      path: ["billingAddress"],
      input: data,
    });
