 * Get UI metadata from a schema
 */
export function getUIMetadata(schema: z.ZodType): UIMetadata | undefined {
  return schema.meta();
}

// ============================================================================
// OPENAPI GENERATION
// ============================================================================

/**
 * OpenAPI Schema Components
 */
export interface OpenAPIComponents {
  schemas: Record<string, Record<string, unknown>>;
}

/**
 * Generate OpenAPI schema components from multiple Zod schemas
 *
 * @example
 * const components = generateOpenAPIComponents({
 *   User: userSchema,
 *   Address: addressSchema,
 *   Order: orderSchema
 * });
 */
export function generateOpenAPIComponents(
  schemas: Record<string, z.ZodType>,
  options: JSONSchemaOptions = {}
): OpenAPIComponents {
  const components: OpenAPIComponents = {
    schemas: {},
  };

  // Track already processed schemas to avoid duplication
  const processed = new Set<string>();

  for (const [name, schema] of Object.entries(schemas)) {
    const result = toJSONSchemaWithDefs(schema, {
      ...options,
      idPrefix: `#/components/schemas/`,
    });

    // Add main schema
    components.schemas[name] = result.schema;

    // Add definitions (avoiding duplicates)
    if (result.definitions) {
      for (const [defName, defSchema] of Object.entries(result.definitions)) {
        if (!processed.has(defName)) {
          components.schemas[defName] = defSchema;
          processed.add(defName);
        }
      }
    }

    processed.add(name);
  }

  return components;
}

/**
 * Generate an OpenAPI request body schema
 *
 * @example
 * const requestBody = generateOpenAPIRequestBody(userSchema, {
 *   description: "User to create"
 * });
 */
export function generateOpenAPIRequestBody(
  schema: z.ZodType,
  options: {
    description?: string;
    required?: boolean;
  } = {}
) {
  const jsonSchema = toJSONSchema(schema, { target: "openapi-3.0" });

  return {
    description: options.description,
    required: options.required ?? true,
    content: {
      "application/json": {
        schema: jsonSchema,
      },
    },
  };
}

/**
 * Generate an OpenAPI response schema
 *
 * @example
 * const response = generateOpenAPIResponse(userSchema, {
 *   description: "User created successfully"
 * });
 */
export function generateOpenAPIResponse(
  schema: z.ZodType,
  options: {
    description?: string;
    status?: string;
  } = {}
) {
  const jsonSchema = toJSONSchema(schema, { target: "openapi-3.0" });

  return {
    description: options.description ?? "Success",
    content: {
      "application/json": {
        schema: jsonSchema,
      },
    },
  };
}

/**
 * Generate OpenAPI error response schema
 */
export function generateOpenAPIErrorResponse(
  description = "Validation error"
) {
  return {
    description,
    content: {
      "application/json": {
        schema: {
          type: "object",
          properties: {
            success: { type: "boolean", const: false },
            error: { type: "string", const: "VALIDATION_ERROR" },
            message: { type: "string" },
            fieldErrors: {
              type: "object",
              additionalProperties: {
                type: "array",
                items: { type: "string" },
              },
            },
            formErrors: {
              type: "array",
              items: { type: "string" },
            },
          },
          required: ["success", "error", "message", "fieldErrors"],
        },
      },
    },
  };
}

// ============================================================================
// TYPE UTILITIES
// ============================================================================

/**
 * Infer JSON Schema type from Zod schema (for TypeScript)
 */
export type JSONSchemaType<T extends z.ZodType> = ReturnType<typeof toJSONSchema<T>>;

/**
 * Schema definition map type
 */
export type SchemaDefinitions = Record<string, Record<string, unknown>>;

// ============================================================================
// EXPORTS
// ============================================================================

export {
  z,
};"}

{"file_path": "/mnt/vdb/djc/work_djc/interactive_data_generation-master_multi_domain_new_struct/workspace/zod--kongyo2_claude_code_203/src/patterns/schema-patterns.ts", "content": "/**
 * Reusable Zod v4 Schema Patterns
 * ================================
 *
 * This module demonstrates proper schema composition, metadata management
 * with registries, and fallback approaches for complex validation scenarios.
 *
 * Key patterns:
 * 1. Schema composition with z.discriminatedUnion
 * 2. Nested discriminated unions for multi-axis branching
 * 3. Fallback approach with z.union + custom refinements
 * 4. Schema reuse and composition via extend/pick/omit
 * 5. Metadata management with custom registries
 * 6. Cross-field validation patterns
 *
 * Architecture Decision:
 * =====================
 * For the checkout form with 3 independent axes (payment × shipping × customer),
 * we use z.discriminatedUnion for each axis independently (perf + type narrowing),
 * then compose them into the overall schema with z.object.
 * Cross-axis rules are handled via .check() / .superRefine() on the composed schema.
 *
 * Why NOT a single discriminated union across all combinations?
 * - 3 payments × 3 shipping × 2 customers = 18 variants
 * - That would be unmaintainable and slow
 * - The axes are independent, so composing them is cleaner
 */

import * as z from "zod";

// ============================================================================
// PATTERN 1: BASIC DISCRIMINATED UNION
// ============================================================================

/**
 * The recommended pattern for branching on a single discriminator key.
 *
 * Benefits:
 * - Efficient parsing (O(1) lookup via discriminator)
 * - TypeScript narrowing works automatically
 * - Clear error messages pointing to the right variant
 */
export function createDiscriminatedUnion<
  Discriminator extends string,
  Variants extends readonly z.ZodObject<{
    [K in Discriminator]: z.ZodType<any>;
  }>[]
>(discriminator: Discriminator, variants: [...Variants]) {
  return z.discriminatedUnion(discriminator, variants);
}

// ============================================================================
// PATTERN 2: CONDITIONAL FIELDS WITH DISCRIMINATED UNIONS
// ============================================================================

/**
 * Pattern: Each variant has its own set of required fields.
 * The discriminator value determines which fields are required.
 *
 * @example
 * // Payment with conditional fields
 * const payment = createConditionalSchema("method", {
 *   credit_card: z.object({
 *     method: z.literal("credit_card"),
 *     cardNumber: z.string().length(16),
 *     cvv: z.string().length(3),
 *   }),
 *   bank_transfer: z.object({
 *     method: z.literal("bank_transfer"),
 *     accountNumber: z.string().min(8),
 *     routingNumber: z.string().length(9),
 *   }),
 * });
 */
export function createConditionalSchema<
  Discriminator extends string,
  VariantMap extends Record<string, z.ZodObject<{
    [K in Discriminator]: z.ZodLiteral<string>;
  }>>
>(
  discriminator: Discriminator,
  variants: VariantMap
) {
  return z.discriminatedUnion(
    discriminator,
    Object.values(variants) as [
      (typeof variants)[keyof VariantMap],
      ...(typeof variants)[keyof VariantMap][]
    ]
  );
}

// ============================================================================
// PATTERN 3: FALLBACK APPROACH WITH z.union + REFINEMENTS
// ============================================================================

/**
 * Use this when:
 * - The discriminator can't be expressed as a simple literal
 *   (e.g., "any string except X and Y")
 * - The discriminator is nested (e.g., subscription.type)
 * - You need overlapping types
 *
 * Tradeoffs:
 * - Slower parsing (tries each variant in order)
 * - TypeScript narrowing less ergonomic
 * - More flexible for complex scenarios
 *
 * @example
 * const paymentWithFallback = createUnionWithFallback([
 *   z.object({ type: z.literal("card"), cardNumber: z.string() }),
 *   z.object({ type: z.literal("bank"), accountNumber: z.string() }),
 *   z.object({ type: z.string(), walletId: z.string() }), // fallback: any other type
 * ]);
 */
export function createUnionWithFallback<Variants extends readonly z.ZodType[]>(
  variants: [...Variants]
) {
  return z.union(variants);
}

/**
 * Exclusive union (XOR) - exactly one variant must match.
 *
 * Use this when options might overlap and you need to ensure
 * exactly one matches (not zero, not multiple).
 *
 * @example
 * const exactlyOne = createExclusiveUnion([
 *   z.object({ type: z.literal("card"), ... }),
 *   z.object({ type: z.literal("bank"), ... }),
 * ]);
 */
export function createExclusiveUnion<Variants extends readonly z.ZodType[]>(
  variants: [...Variants]
) {
  return z.xor(variants);
}

// ============================================================================
// PATTERN 4: CROSS-FIELD VALIDATION
// ============================================================================

/**
 * Cross-field validation pattern using .check() on the composed schema.
 *
 * In Zod v4, cross-field validation is done at the object level
 * using .refine() or .check() with path targeting.
 *
 * Key: Use the `path` parameter to attach errors to the correct field.
 *
 * @example
 * const form = crossFieldValidation(
 *   z.object({
 *     password: z.string().min(8),
 *     confirmPassword: z.string(),
 *   }),
 *   [
 *     {
 *       check: (data) => data.password === data.confirmPassword,
 *       message: "Passwords don't match",
 *       path: ["confirmPassword"],
 *     }
 *   ]
 * );
 */
export function crossFieldValidation<
  T extends z.ZodObject<any>,
  Checks extends readonly {
    check: (data: z.infer<T>) => boolean;
    message: string;
    path?: string[];
  }[]
>(baseSchema: T, checks: Checks) {
  let schema: z.ZodType = baseSchema;

  for (const { check, message, path } of checks) {
    schema = schema.refine(check, {
      error: message,
      path: path ?? [],
    });
  }

  return schema;
}

/**
 * Advanced cross-field validation with conditional execution.
 *
 * Uses the `when` parameter to control when refinements run,
 * ensuring they execute even if other fields have errors.
 *
 * @example
 * const schema = advancedCrossFieldValidation(
 *   baseSchema,
 *   [
 *     {
 *       check: (data) => data.endDate > data.startDate,
 *       message: "End date must be after start date",
 *       path: ["endDate"],
 *       // Only run if both dates are present
 *       when: (payload) => payload.issues.every(
 *         iss => iss.path?.[0] !== "startDate" && iss.path?.[0] !== "endDate"
 *       )
 *     }
 *   ]
 * );
 */
export function advancedCrossFieldValidation<
  T extends z.ZodObject<any>,
  Checks extends readonly {
    check: (data: z.infer<T>) => boolean;
    message: string;
    path?: string[];
    when?: (payload: { value: z.infer<T>; issues: z.ZodIssue[] }) => boolean;
  }[]
>(baseSchema: T, checks: Checks) {
  let schema: z.ZodType = baseSchema;

  for (const { check, message, path, when } of checks) {
    schema = schema.refine(check, {
      error: message,
      path: path ?? [],
      ...(when ? { when } : {}),
    });
  }

  return schema;
}

// ============================================================================
// PATTERN 5: MULTI-STEP FORM VALIDATION
// ============================================================================

/**
 * Multi-step form validation pattern.
 *
 * Each step has its own schema, and there's a composed schema
 * for final validation. Partial validation is supported for
 * "save and continue" functionality.
 *
 * @example
 * const steps = createMultiStepForm({
 *   customer: customerSchema,
 *   shipping: shippingSchema,
 *   payment: paymentSchema,
 * });
 *
 * // Validate single step
 * steps.validateStep("customer", data);
 *
 * // Validate all steps
 * steps.validateAll(allData);
 */
export function createMultiStepForm<
  Steps extends Record<string, z.ZodType>
>(steps: Steps) {
  return {
    /** Get schema for a specific step */
    getStepSchema: <K extends keyof Steps>(step: K): Steps[K] => {
      return steps[step];
    },

    /** Validate a single step */
    validateStep: <K extends keyof Steps>(
      step: K,
      data: unknown
    ): z.SafeParseReturnType<unknown, z.infer<Steps[K]>> => {
      return steps[step].safeParse(data);
    },

    /** Validate all steps and return combined errors */
    validateAll: (
      data: Record<string, unknown>
    ): {
      success: boolean;
      errors: Record<string, Record<string, string[]>>;
    } => {
      const allErrors: Record<string, Record<string, string[]>> = {};
      let success = true;

      for (const [stepName, schema] of Object.entries(steps)) {
        const stepData = data[stepName];
        const result = schema.safeParse(stepData);

        if (!result.success) {
          success = false;
          const fieldErrors: Record<string, string[]> = {};
          for (const issue of result.error.issues) {
            const path = issue.path.join(".");
            if (!fieldErrors[path]) fieldErrors[path] = [];
            fieldErrors[path].push(issue.message);
          }
          allErrors[stepName] = fieldErrors;
        }
      }

      return { success, errors: allErrors };
    },

    /** Create the composed schema for all steps */
    composedSchema: z.object(
      Object.fromEntries(
        Object.entries(steps).map(([key, schema]) => [key, schema])
      )
    ) as z.ZodObject<{
      [K in keyof Steps]: Steps[K];
    }>,

    /** Get step names */
    stepNames: Object.keys(steps) as (keyof Steps)[],
  };
}

// ============================================================================
// PATTERN 6: SCHEMA COMPOSITION WITH REUSE
// ============================================================================

/**
 * Create a reusable base schema that can be extended.
 *
 * Uses Zod v4's recommended pattern of schema destructuring
 * for best TypeScript performance.
 *
 * @example
 * const baseAddress = createBaseSchema("address", z.object({
 *   line1: z.string(),
 *   city: z.string(),
 *   country: z.string().length(2),
 * }));
 *
 * const usAddress = extendSchema(baseAddress, {
 *   state: z.string(),
 *   zipCode: z.string().regex(/^\d{5}(-\d{4})?$/),
 * });
 *
 * const ukAddress = extendSchema(baseAddress, {
 *   county: z.string(),
 *   postcode: z.string().regex(/^[A-Z]{1,2}\d[A-Z\d]?\s*\d[A-Z]{2}$/),
 * });
 */
export function createBaseSchema<T extends z.ZodRawShape>(
  name: string,
  shape: T
) {
  const schema = z.object(shape);
  schema.meta({
    id: name,
    title: name,
  });
  return schema;
}

/**
 * Extend a base schema with additional fields.
 * Uses object destructuring for best TypeScript performance.
 */
export function extendSchema<
  T extends z.ZodObject<any>,
  Extension extends z.ZodRawShape
>(base: T, extension: Extension) {
  return z.object({
    ...base.shape,
    ...extension,
  });
}

/**
 * Create an internationalized address schema variant
 */
export function createAddressSchema(countrySpecific: {
  state?: z.ZodType;
  postalCode?: z.ZodType;
} = {}) {
  return z.object({
    line1: z.string().min(1),
    line2: z.string().optional(),
    city: z.string().min(1),
    state: countrySpecific.state ?? z.string().min(1),
    postalCode: countrySpecific.postalCode ?? z.string().min(1),
    country: z.string().length(2),
  });
}

// ============================================================================
// PATTERN 7: NESTED DISCRIMINATED UNIONS
// ============================================================================

/**
 * Nested discriminated unions for complex multi-level branching.
 *
 * Zod v4 supports nested discriminated unions and will automatically
 * optimize the parsing strategy.
 *
 * @example
 * const nestedUnion = createNestedDiscriminatedUnion(
 *   z.discriminatedUnion("level1", [
 *     z.object({
 *       level1: z.literal("A"),
 *       data: z.discriminatedUnion("level2", [
 *         z.object({ level2: z.literal("X"), value: z.string() }),
 *         z.object({ level2: z.literal("Y"), value: z.number() }),
 *       ]),
 *     }),
 *     z.object({
 *       level1: z.literal("B"),
 *       data: z.string(),
 *     }),
 *   ])
 * );
 */
export function createNestedDiscriminatedUnion<T extends z.ZodType>(
  schema: T
): T {
  return schema;
}

// ============================================================================
// PATTERN 8: CONDITIONAL REQUIREMENT PATTERN
// ============================================================================

/**
 * Make a field conditionally required based on another field's value.
 *
 * Uses .refine() at the object level to conditionally require fields.
 * The error is attached to the conditional field via `path`.
 *
 * @example
 * const schema = conditionalRequired(
 *   z.object({
 *     hasCompany: z.boolean(),
 *     companyName: z.string().optional(),
 *   }),
 *   {
 *     field: "companyName",
 *     dependsOn: "hasCompany",
 *     when: (value) => value === true,
 *     message: "Company name is required when hasCompany is true",
 *   }
 * );
 */
export function conditionalRequired<
  T extends z.ZodObject<any>,
  Field extends keyof z.infer<T>,
  DependentField extends keyof z.infer<T>
>(
  schema: T,
  config: {
    field: Field;
    dependsOn: DependentField;
    when: (value: z.infer<T>[DependentField]) => boolean;
    message?: string;
  }
) {
  return schema.refine(
    (data) => {
      const dependentValue = data[config.dependsOn];
      if (config.when(dependentValue)) {
        // Check if the field has a value
        const fieldValue = data[config.field];
        return fieldValue !== undefined && fieldValue !== null && fieldValue !== "";
      }
      return true;
    },
    {
      error: config.message ?? `${String(config.field)} is required`,
      path: [config.field as string],
    }
  );
}

// ============================================================================
// PATTERN 9: REGISTRY-BASED METADATA MANAGEMENT
// ============================================================================

/**
 * A metadata management system using Zod v4's registry API.
 *
 * Registries decouple metadata from schemas, allowing:
 * - Multiple metadata sets per schema
 * - Schema reuse without metadata conflicts
 * - Clean separation of concerns
 */

/**
 * Create a typed registry for domain-specific metadata
 */
export function createMetadataRegistry<
  Meta extends Record<string, unknown>
>() {
  return z.registry<Meta>();
}

/**
 * Example: Form field metadata registry
 */
export interface FormFieldMeta {
  label: string;
  placeholder?: string;
  helpText?: string;
  group?: string;
  order?: number;
  hidden?: boolean;
  disabled?: boolean;
  component?: "text" | "select" | "checkbox" | "radio" | "textarea" | "date" | "file";
  options?: { label: string; value: string }[];
}

export const formFieldRegistry = createMetadataRegistry<FormFieldMeta>();

/**
 * Register a schema with form field metadata
 */
export function withFormField<T extends z.ZodType>(
  schema: T,
  meta: FormFieldMeta
): T {
  schema.register(formFieldRegistry, meta);
  return schema;
}

/**
 * Example: API documentation metadata registry
 */
export interface APIDocMeta {
  endpoint?: string;
  method?: "GET" | "POST" | "PUT" | "PATCH" | "DELETE";
  pathParam?: boolean;
  queryParam?: boolean;
  header?: boolean;
  requestBody?: boolean;
}

export const apiDocRegistry = createMetadataRegistry<APIDocMeta>();

/**
 * Register a schema with API documentation metadata
 */
export function withAPIDoc<T extends z.ZodType>(
  schema: T,
  meta: APIDocMeta
): T {
  schema.register(apiDocRegistry, meta);
  return schema;
}

// ============================================================================
// PATTERN 10: VALIDATION PIPELINE
// ============================================================================

/**
 * Create a validation pipeline that runs multiple validation steps.
 *
 * Useful for complex forms where validation needs to happen
 * in stages (e.g., structural validation -> business rules -> async checks).
 *
 * @example
 * const pipeline = createValidationPipeline(checkoutSchema)
 *   .addRule("Business customers need VAT for EU", (data) => {
 *     if (data.customer.type === "business" && isEU(data.customer.businessAddress.country)) {
 *       return !!data.customer.vatNumber;
 *     }
 *     return true;
 *   }, { path: ["customer", "vatNumber"] })
 *   .addRule("Pickup requires location", (data) => {
 *     if (data.shipping.option === "pickup") {
 *       return !!data.shipping.pickupLocationId;
 *     }
 *     return true;
 *   }, { path: ["shipping", "pickupLocationId"] })
 *   .build();
 */
export function createValidationPipeline<T extends z.ZodType>(baseSchema: T) {
  const rules: Array<{
    name: string;
    check: (data: z.infer<T>) => boolean;
    message: string;
    path?: string[];
    abort?: boolean;
  }> = [];

  return {
    addRule: (
      name: string,
      check: (data: z.infer<T>) => boolean,
      options: {
        message?: string;
        path?: string[];
        abort?: boolean;
      } = {}
    ) => {
      rules.push({
        name,
        check,
        message: options.message ?? `Validation failed: ${name}`,
        path: options.path,
        abort: options.abort,
      });
      return createValidationPipeline(baseSchema);
    },

    build: () => {
      let schema: z.ZodType = baseSchema;

      for (const rule of rules) {
        schema = schema.refine(rule.check, {
          error: rule.message,
          path: rule.path ?? [],
          abort: rule.abort,
        });
      }

      return schema;
    },
  };
}

// ============================================================================
// PATTERN 11: SCHEMA VERSIONING
// ============================================================================

/**
 * Versioned schemas for API evolution.
 *
 * Allows maintaining multiple versions of a schema and validating
 * against the correct version based on an API version header.
 *
 * @example
 * const versions = createVersionedSchema({
 *   v1: z.object({ name: z.string(), email: z.string() }),
 *   v2: z.object({ name: z.string(), email: z.email(), phone: z.string().optional() }),
 * });
 *
 * versions.validate("v1", { name: "John", email: "invalid" }); // passes
 * versions.validate("v2", { name: "John", email: "invalid" }); // fails
 */
export function createVersionedSchema<
  Versions extends Record<string, z.ZodType>
>(versions: Versions) {
  return {
    /** Get schema for a specific version */
    getSchema: <V extends keyof Versions>(version: V): Versions[V] => {
      return versions[version];
    },

    /** Validate data against a specific version */
    validate: <V extends keyof Versions>(
      version: V,
      data: unknown
    ): z.SafeParseReturnType<unknown, z.infer<Versions[V]>> => {
      return versions[version].safeParse(data);
    },

    /** Get the latest version */
    latest: versions[Object.keys(versions).pop() as keyof Versions],

    /** Get all version names */
    versionNames: Object.keys(versions) as (keyof Versions)[],
  };
}

// ============================================================================
// EXPORTS
// ============================================================================

export {
  z,
};"}

