     1→using System;
     2→using System.Threading.Tasks;
     3→using Microsoft.Azure.Functions.Worker;
     4→using Microsoft.DurableTask;
     5→using Microsoft.Extensions.Logging;
     6→
     7→namespace ContosoBank.PaymentGateway
     8→{
     9→    public class PaymentOrchestrator
    10→    {
    11→        private readonly ILogger _logger;
    12→
    13→        public PaymentOrchestrator(ILogger<PaymentOrchestrator> logger)
    14→        {
    15→            _logger = logger;
    16→        }
    17→
    18→        [Function("PaymentOrchestrator")]
    19→        public async Task<string> RunOrchestrator(
    20→            [OrchestrationTrigger] TaskOrchestrationContext context)
    21→        {
    22→            var input = context.GetInput<PaymentRequest>();
    23→            _logger.LogInformation("Starting payment orchestration for TransactionId: {TransactionId}", input.TransactionId);
    24→
    25→            // Step 1: Validate payment
    26→            var validationResult = await context.CallActivityAsync<ValidationResult>(
    27→                nameof(ValidatePaymentActivity), input);
    28→
    29→            if (!validationResult.IsValid)
    30→            {
    31→                return $"Payment validation failed: {validationResult.Reason}";
    32→            }
    33→
    34→            // Step 2: Reserve funds from source account
    35→            try
    36→            {
    37→                await context.CallActivityAsync<AccountOperationResult>(
    38→                    nameof(ReserveFundsActivity),
    39→                    new AccountOperation { AccountId = input.SourceAccountId, Amount = input.Amount, TransactionId = input.TransactionId });
    40→            }
    41→            catch (TaskFailedException ex)
    42→            {
    43→                _logger.LogError("Fund reservation failed for TransactionId: {TransactionId}. Error: {Error}", input.TransactionId, ex.Message);
    44→                return $"Payment failed: Could not reserve funds. {ex.Message}";
    45→            }
    46→
    47→            // Step 3: Credit destination account (pivot transaction)
    48→            try
    49→            {
    50→                await context.CallActivityAsync<AccountOperationResult>(
    51→                    nameof(CreditAccountActivity),
    52→                    new AccountOperation { AccountId = input.DestinationAccountId, Amount = input.Amount, TransactionId = input.TransactionId });
    53→            }
    54→            catch (TaskFailedException ex)
    55→            {
    56→                _logger.LogError("Credit failed for TransactionId: {TransactionId}. Compensating... Error: {Error}", input.TransactionId, ex.Message);
    57→
    58→                // Compensating transaction: release reserved funds
    59→                await context.CallActivityAsync<AccountOperationResult>(
    60→                    nameof(ReleaseFundsActivity),
    61→                    new AccountOperation { AccountId = input.SourceAccountId, Amount = input.Amount, TransactionId = input.TransactionId });
    62→
    63→                return $"Payment failed: Could not credit destination account. Compensation completed. {ex.Message}";
    64→            }
    65→
    66→            // Step 4: Record transaction in ledger
    67→            try
    68→            {
    69→                await context.CallActivityAsync<LedgerResult>(
    70→                    nameof(RecordTransactionActivity),
    71→                    new LedgerEntry { TransactionId = input.TransactionId, SourceAccountId = input.SourceAccountId, DestinationAccountId = input.DestinationAccountId, Amount = input.Amount, Currency = input.Currency });
    72→            }
    73→            catch (TaskFailedException ex)
    74→            {
    75→                _logger.LogError("Ledger recording failed for TransactionId: {TransactionId}. Error: {Error}", input.TransactionId, ex.Message);
    76→                // Note: Ledger recording is retryable - the funds have already moved
    77→                // In production, this would trigger an alert for manual reconciliation
    78→                return $"Payment processed but ledger recording failed. Manual reconciliation required. {ex.Message}";
    79→            }
    80→
    81→            // Step 5: Send notification
    82→            await context.CallActivityAsync(nameof(SendNotificationActivity),
    83→                new Notification { TransactionId = input.TransactionId, Recipient = input.SourceAccountId, Status = "Completed" });
    84→
    85→            return $"Payment of {input.Amount} {input.Currency} from {input.SourceAccountId} to {input.DestinationAccountId} completed successfully.";
    86→        }
    87→    }
    88→
    89→    // Data models
    90→    public class PaymentRequest
    91→    {
    92→        public string TransactionId { get; set; }
    93→        public string SourceAccountId { get; set; }
    94→        public string DestinationAccountId { get; set; }
    95→        public decimal Amount { get; set; }
    96→        public string Currency { get; set; }
    97→    }
    98→
    99→    public class ValidationResult
   100→    {
   101→        public bool IsValid { get; set; }
   102→        public string Reason { get; set; }
   103→    }
   104→
   105→    public class AccountOperation
   106→    {
   107→        public string AccountId { get; set; }
   108→        public decimal Amount { get; set; }
   109→        public string TransactionId { get; set; }
   110→    }
   111→
   112→    public class AccountOperationResult
   113→    {
   114→        public bool Success { get; set; }
   115→        public string Message { get; set; }
   116→        public string OperationId { get; set; }
   117→    }
   118→
   119→    public class LedgerEntry
   120→    {
