    {
        private readonly ILogger _logger;

        public CurrencyConversionActivity(ILogger<CurrencyConversionActivity> logger)
        {
            _logger = logger;
        }

        /// <summary>
        /// Converts the payment amount from source currency to destination currency.
        /// This is a COMPENSABLE transaction in the Saga pattern — it must be placed
        /// BEFORE the pivot transaction (CreditAccount) so that it can be undone if a
        /// subsequent step fails. If currency conversion fails, no compensation is
        /// needed because no state has been mutated yet. If a later step fails after
        /// conversion succeeds, the ReverseCurrencyConversionActivity compensates by
        /// releasing the rate lock and reversing the conversion record.
        ///
        /// Rationale for compensable (before pivot) vs. retryable (after pivot):
        /// - Per Microsoft's Saga pattern documentation (learn.microsoft.com/azure/architecture/patterns/saga),
        ///   compensable transactions "can be undone or compensated for by other transactions
        ///   with the opposite effect." Currency conversion creates a rate lock and conversion
        ///   record that must be reversible if downstream steps fail.
        /// - The "Pessimistic view" countermeasure from the same documentation states:
        ///   "Reorder the sequence of the saga so that data updates occur in retryable
        ///   transactions to eliminate dirty reads." Since fund reservation and credit
        ///   operations depend on the converted amount, conversion must complete (and be
        ///   compensable) before those steps execute.
        /// - Per the Compensating Transaction pattern (learn.microsoft.com/azure/architecture/patterns/compensating-transaction),
        ///   "compensating transactions don't always work" and should be idempotent.
        ///   Currency conversion is naturally idempotent when using a conversion ID.
        /// </summary>
        [Function(nameof(CurrencyConversionActivity))]
        public Task<CurrencyConversionResult> Run([ActivityTrigger] CurrencyConversionRequest input)
        {
            _logger.LogInformation(
                "Converting {Amount} from {SourceCurrency} to {DestinationCurrency} for transaction {TransactionId}",
                input.Amount, input.SourceCurrency, input.DestinationCurrency, input.TransactionId);

            if (string.IsNullOrEmpty(input.SourceCurrency) || string.IsNullOrEmpty(input.DestinationCurrency))
            {
                throw new ArgumentException("Source and destination currencies are required for conversion.");
            }

            if (input.Amount <= 0)
            {
                throw new ArgumentException("Conversion amount must be greater than zero.");
            }

            // Same currency — no conversion needed, pass through
            if (string.Equals(input.SourceCurrency, input.DestinationCurrency, StringComparison.OrdinalIgnoreCase))
            {
                _logger.LogInformation(
                    "Same currency ({Currency}) for transaction {TransactionId}. No conversion required.",
                    input.SourceCurrency, input.TransactionId);

                return Task.FromResult(new CurrencyConversionResult
                {
                    Success = true,
                    ConversionId = null,
                    OriginalAmount = input.Amount,
                    ConvertedAmount = input.Amount,
                    SourceCurrency = input.SourceCurrency,
                    DestinationCurrency = input.DestinationCurrency,
                    ExchangeRate = 1.0m,
                    ConversionRequired = false,
                    Message = "No conversion required — same currency."
                });
            }

            // Simulate calling an external FX rate service
            // In production, this would call a service like Reuters, Bloomberg, or Azure-based FX API
            var exchangeRate = GetExchangeRate(input.SourceCurrency, input.DestinationCurrency);
            var convertedAmount = Math.Round(input.Amount * exchangeRate, 2);

            // Simulate rate lock creation — in production, this would persist to Cosmos DB
            // with a TTL-based lock to ensure the rate is honored for this transaction
            var conversionId = Guid.NewGuid().ToString();

            _logger.LogInformation(
                "Currency conversion completed for transaction {TransactionId}. " +
                "ConversionId: {ConversionId}, Rate: {ExchangeRate}, " +
                "Original: {OriginalAmount} {SourceCurrency}, Converted: {ConvertedAmount} {DestinationCurrency}",
                input.TransactionId, conversionId, exchangeRate,
                input.Amount, input.SourceCurrency, convertedAmount, input.DestinationCurrency);

            return Task.FromResult(new CurrencyConversionResult
            {
                Success = true,
                ConversionId = conversionId,
                OriginalAmount = input.Amount,
                ConvertedAmount = convertedAmount,
                SourceCurrency = input.SourceCurrency,
                DestinationCurrency = input.DestinationCurrency,
                ExchangeRate = exchangeRate,
                ConversionRequired = true,
                Message = "Currency conversion completed successfully."
            });
        }

        /// <summary>
        /// Simulates retrieving an exchange rate from an FX rate provider.
        /// In production, this would call an external rate service with caching and fallback.
        /// </summary>
        private decimal GetExchangeRate(string sourceCurrency, string destinationCurrency)
        {
            // Simulated exchange rates for demonstration
            var rates = new Dictionary<string, decimal>(StringComparer.OrdinalIgnoreCase)
            {
                { "USD-EUR", 0.92m },
                { "EUR-USD", 1.087m },
                { "USD-GBP", 0.79m },
                { "GBP-USD", 1.266m },
                { "EUR-GBP", 0.86m },
                { "GBP-EUR", 1.163m },
                { "USD-JPY", 154.5m },
                { "JPY-USD", 0.00647m },
                { "USD-CAD", 1.37m },
                { "CAD-USD", 0.73m },
                { "USD-AUD", 1.53m },
                { "AUD-USD", 0.654m },
                { "EUR-CHF", 0.94m },
                { "CHF-EUR", 1.064m }
            };

            var key = $"{sourceCurrency}-{destinationCurrency}";
            if (rates.TryGetValue(key, out var rate))
            {
                return rate;
            }

            throw new InvalidOperationException(
                $"Exchange rate not available for {sourceCurrency} to {destinationCurrency}. " +
                "Please verify the currency codes are supported.");
        }
    }

    /// <summary>
    /// Compensating transaction for CurrencyConversionActivity.
    /// Per the Compensating Transaction pattern (learn.microsoft.com/azure/architecture/patterns/compensating-transaction):
    /// "You should define the steps in a compensating transaction as idempotent commands.
    ///  If you do, the steps can be repeated if the compensating transaction itself fails."
    ///
    /// This activity releases the rate lock and creates a reversal record to maintain
    /// audit trail consistency. It is idempotent — calling it multiple times with the
    /// same ConversionId has no additional effect.
    /// </summary>
    public class ReverseCurrencyConversionActivity
    {
        private readonly ILogger _logger;

        public ReverseCurrencyConversionActivity(ILogger<ReverseCurrencyConversionActivity> logger)
        {
            _logger = logger;
        }

        [Function(nameof(ReverseCurrencyConversionActivity))]
        public Task<CurrencyConversionResult> Run([ActivityTrigger] CurrencyConversionRequest input)
        {
            _logger.LogInformation(
                "Reversing currency conversion for transaction {TransactionId}, " +
                "ConversionId: {ConversionId}",
                input.TransactionId, input.ConversionIdToReverse ?? "N/A");

            // If no conversion was required (same currency), there's nothing to reverse
            if (string.IsNullOrEmpty(input.ConversionIdToReverse))
            {
                _logger.LogInformation(
                    "No conversion to reverse for transaction {TransactionId}. " +
                    "Original transaction was same-currency.",
                    input.TransactionId);

                return Task.FromResult(new CurrencyConversionResult
                {
                    Success = true,
                    ConversionId = null,
                    OriginalAmount = input.Amount,
                    ConvertedAmount = input.Amount,
                    SourceCurrency = input.SourceCurrency,
                    DestinationCurrency = input.DestinationCurrency,
                    ExchangeRate = 1.0m,
                    ConversionRequired = false,
                    Message = "No conversion reversal required."
                });
            }

            // Simulate releasing the rate lock and creating a reversal record
            // In production, this would:
            // 1. Mark the conversion record as REVERSED in Cosmos DB
            // 2. Release the rate lock
            // 3. Create a reversal audit entry
            // The operation is idempotent — repeated calls with the same ConversionId
            // will find the record already reversed and return success

            _logger.LogWarning(
                "Currency conversion REVERSED for transaction {TransactionId}. " +
                "ConversionId: {ConversionId} has been marked as reversed. " +
                "Rate lock released.",
                input.TransactionId, input.ConversionIdToReverse);

            return Task.FromResult(new CurrencyConversionResult
            {
                Success = true,
                ConversionId = input.ConversionIdToReverse,
                OriginalAmount = input.Amount,
                ConvertedAmount = input.Amount,
                SourceCurrency = input.SourceCurrency,
                DestinationCurrency = input.DestinationCurrency,
                ExchangeRate = 1.0m,
                ConversionRequired = false,
                Message = "Currency conversion reversal completed successfully."
            });
        }
    }

