using System.Threading.Tasks;
using Microsoft.Azure.Functions.Worker;
using Microsoft.DurableTask;
using Microsoft.Extensions.Logging;

namespace ContosoBank.PaymentGateway
{
    public class PaymentOrchestrator
    {
        private readonly ILogger _logger;

        public PaymentOrchestrator(ILogger<PaymentOrchestrator> logger)
        {
            _logger = logger;
        }

        [Function("PaymentOrchestrator")]
        public async Task<string> RunOrchestrator(
            [OrchestrationTrigger] TaskOrchestrationContext context)
        {
            var input = context.GetInput<PaymentRequest>();
            _logger.LogInformation("Starting payment orchestration for TransactionId: {TransactionId}", input.TransactionId);

            // Determine if cross-border conversion is needed
            bool isCrossBorder = !string.Equals(input.SourceCurrency, input.DestinationCurrency, StringComparison.OrdinalIgnoreCase);
            CurrencyConversionResult conversionResult = null;

            // ============================================================
            // COMPENSABLE STEP 1: Validate payment
            // ============================================================
            var validationResult = await context.CallActivityAsync<ValidationResult>(
                nameof(ValidatePaymentActivity), input);

            if (!validationResult.IsValid)
            {
                return $"Payment validation failed: {validationResult.Reason}";
            }

            // ============================================================
            // COMPENSABLE STEP 2: Currency conversion (cross-border only)
            // This step MUST be before the pivot (CreditAccount) because:
            //
            // 1. Per Microsoft's Saga pattern documentation
            //    (learn.microsoft.com/azure/architecture/patterns/saga),
            //    compensable transactions "can be undone or compensated for
            //    by other transactions with the opposite effect." Currency
            //    conversion creates a rate lock and conversion record that
            //    must be reversible if downstream steps fail.
            //
            // 2. The "Pessimistic view" countermeasure from the same doc
            //    states: "Reorder the sequence of the saga so that data
            //    updates occur in retryable transactions to eliminate dirty
            //    reads." Since fund reservation and credit operations depend
            //    on the converted amount, conversion must complete first.
            //
            // 3. Per the Compensating Transaction pattern
            //    (learn.microsoft.com/azure/architecture/patterns/compensating-transaction),
            //    "compensating transactions don't always work" and should be
            //    idempotent. Currency conversion is naturally idempotent when
            //    using a conversion ID.
            // ============================================================
            if (isCrossBorder)
            {
                try
                {
                    conversionResult = await context.CallActivityAsync<CurrencyConversionResult>(
                        nameof(CurrencyConversionActivity),
                        new CurrencyConversionRequest
                        {
                            TransactionId = input.TransactionId,
                            SourceCurrency = input.SourceCurrency,
                            DestinationCurrency = input.DestinationCurrency,
                            Amount = input.Amount
                        });

                    _logger.LogInformation(
                        "Currency conversion completed for TransactionId: {TransactionId}. " +
                        "Converted {OriginalAmount} {SourceCurrency} to {ConvertedAmount} {DestinationCurrency} " +
                        "at rate {ExchangeRate}",
                        input.TransactionId,
                        conversionResult.OriginalAmount, conversionResult.SourceCurrency,
                        conversionResult.ConvertedAmount, conversionResult.DestinationCurrency,
                        conversionResult.ExchangeRate);
                }
                catch (TaskFailedException ex)
                {
                    _logger.LogError(
                        "Currency conversion failed for TransactionId: {TransactionId}. Error: {Error}",
                        input.TransactionId, ex.Message);
                    return $"Payment failed: Currency conversion error. {ex.Message}";
                }
            }
            else
            {
                // Same currency — no conversion needed, create a passthrough result
                conversionResult = new CurrencyConversionResult
                {
                    Success = true,
                    ConversionId = null,
                    OriginalAmount = input.Amount,
                    ConvertedAmount = input.Amount,
                    SourceCurrency = input.SourceCurrency,
                    DestinationCurrency = input.DestinationCurrency,
                    ExchangeRate = 1.0m,
                    ConversionRequired = false,
                    Message = "No conversion required."
                };
            }

            // Use the converted amount for all downstream operations
            decimal effectiveAmount = conversionResult.ConvertedAmount;

            // ============================================================
            // COMPENSABLE STEP 3: Reserve funds from source account
            // Uses original amount (source currency) for reservation
            // ============================================================
            try
            {
                await context.CallActivityAsync<AccountOperationResult>(
                    nameof(ReserveFundsActivity),
                    new AccountOperation { AccountId = input.SourceAccountId, Amount = input.Amount, TransactionId = input.TransactionId });
            }
            catch (TaskFailedException ex)
            {
                _logger.LogError("Fund reservation failed for TransactionId: {TransactionId}. Error: {Error}", input.TransactionId, ex.Message);

                // Compensate: reverse currency conversion if it was performed
                if (conversionResult.ConversionRequired)
                {
                    await CompensateCurrencyConversion(context, input, conversionResult);
                }

                return $"Payment failed: Could not reserve funds. {ex.Message}";
            }

            // ============================================================
            // PIVOT TRANSACTION (Step 4): Credit destination account
            // This is the point of no return. After this succeeds,
            // compensable transactions are no longer relevant.
            // Uses converted amount (destination currency) for credit.
            // ============================================================
            try
            {
                await context.CallActivityAsync<AccountOperationResult>(
                    nameof(CreditAccountActivity),
                    new AccountOperation { AccountId = input.DestinationAccountId, Amount = effectiveAmount, TransactionId = input.TransactionId });
            }
            catch (TaskFailedException ex)
            {
                _logger.LogError("Credit failed for TransactionId: {TransactionId}. Compensating... Error: {Error}", input.TransactionId, ex.Message);

                // Compensate in reverse order of completed compensable steps:
                // 1. Release reserved funds (most recent compensable step)
                await context.CallActivityAsync<AccountOperationResult>(
                    nameof(ReleaseFundsActivity),
                    new AccountOperation { AccountId = input.SourceAccountId, Amount = input.Amount, TransactionId = input.TransactionId });

                // 2. Reverse currency conversion (earliest compensable step)
                if (conversionResult.ConversionRequired)
                {
                    await CompensateCurrencyConversion(context, input, conversionResult);
                }

                return $"Payment failed: Could not credit destination account. Compensation completed. {ex.Message}";
            }

            // ============================================================
            // RETRYABLE STEP 5: Record transaction in ledger
            // After the pivot, all steps must eventually succeed.
            // Per the Saga pattern, retryable transactions are idempotent
            // and help ensure the saga can reach its final state.
            // ============================================================
            try
            {
                await context.CallActivityAsync<LedgerResult>(
                    nameof(RecordTransactionActivity),
                    new LedgerEntry
                    {
                        TransactionId = input.TransactionId,
                        SourceAccountId = input.SourceAccountId,
                        DestinationAccountId = input.DestinationAccountId,
                        Amount = effectiveAmount,
                        Currency = input.DestinationCurrency,
                        SourceAmount = input.Amount,
                        SourceCurrency = input.SourceCurrency,
                        ExchangeRate = conversionResult.ExchangeRate,
                        ConversionId = conversionResult.ConversionId
                    });
            }
            catch (TaskFailedException ex)
            {
                _logger.LogError("Ledger recording failed for TransactionId: {TransactionId}. Error: {Error}", input.TransactionId, ex.Message);
                // Note: Ledger recording is retryable - the funds have already moved
                // In production, this would trigger an alert for manual reconciliation
                // Per the Compensating Transaction pattern: "In some cases, manual
                // intervention might be the only way to recover from a step that has failed."
                return $"Payment processed but ledger recording failed. Manual reconciliation required. {ex.Message}";
            }

            // ============================================================
            // RETRYABLE STEP 6: Send notification
            // Non-critical operation, no compensation needed.
            // ============================================================
            var notificationMessage = isCrossBorder
                ? $"Cross-border payment of {input.Amount} {input.SourceCurrency} " +
                  $"(converted to {effectiveAmount} {input.DestinationCurrency}) " +
                  $"from {input.SourceAccountId} to {input.DestinationAccountId} completed."
                : $"Payment of {input.Amount} {input.Currency} " +
                  $"from {input.SourceAccountId} to {input.DestinationAccountId} completed.";

            await context.CallActivityAsync(nameof(SendNotificationActivity),
                new Notification { TransactionId = input.TransactionId, Recipient = input.SourceAccountId, Status = "Completed", Message = notificationMessage });

            return isCrossBorder
                ? $"Cross-border payment of {input.Amount} {input.SourceCurrency} " +
                  $"(converted to {effectiveAmount} {input.DestinationCurrency} at rate {conversionResult.ExchangeRate}) " +
                  $"from {input.SourceAccountId} to {input.DestinationAccountId} completed successfully."
                : $"Payment of {input.Amount} {input.Currency} from {input.SourceAccountId} to {input.DestinationAccountId} completed successfully.";
        }

        /// <summary>
        /// Compensates the currency conversion step by calling the
        /// ReverseCurrencyConversionActivity. This method encapsulates the
        /// compensation logic for currency conversion, ensuring it is applied
        /// consistently whenever compensation is needed.
        ///
        /// Per the Compensating Transaction pattern (learn.microsoft.com/azure/architecture/patterns/compensating-transaction):
        /// "The order of the steps in the compensating transaction isn't necessarily
        /// the exact opposite of the steps in the original operation. For example,
        /// one data store might be more sensitive to inconsistencies than another.
        /// The steps in the compensating transaction that undo the changes to this
        /// store should occur first."
        ///
        /// In our case, fund release is compensated before currency conversion
        /// reversal because the account balance is more sensitive to inconsistency
        /// than the conversion rate lock.
        /// </summary>
        private async Task CompensateCurrencyConversion(
            TaskOrchestrationContext context,
            PaymentRequest input,
            CurrencyConversionResult conversionResult)
        {
            _logger.LogWarning(
                "Compensating currency conversion for TransactionId: {TransactionId}, ConversionId: {ConversionId}",
                input.TransactionId, conversionResult.ConversionId);

            try
            {
                await context.CallActivityAsync<CurrencyConversionResult>(
                    nameof(ReverseCurrencyConversionActivity),
                    new CurrencyConversionRequest
                    {
                        TransactionId = input.TransactionId,
                        SourceCurrency = input.SourceCurrency,
                        DestinationCurrency = input.DestinationCurrency,
                        Amount = input.Amount,
                        ConversionIdToReverse = conversionResult.ConversionId
                    });
            }
            catch (TaskFailedException compEx)
            {
                // Per the Compensating Transaction pattern:
                // "Compensating transactions don't always work. You should define the
                //  steps in a compensating transaction as idempotent commands."
                // If compensation fails, log and alert for manual intervention.
                _logger.LogError(
                    "CRITICAL: Currency conversion compensation failed for TransactionId: {TransactionId}, " +
                    "ConversionId: {ConversionId}. Manual intervention required. Error: {Error}",
                    input.TransactionId, conversionResult.ConversionId, compEx.Message);
            }
        }
    }

